object Main extends App {

  val awsManager = AwsServiceManager.withDefaultCredentials(Region.US_EAST_1)

  if (awsManager.validateCredentials()) {
    println("Credentials validated successfully")

    // S3 operations
    awsManager.s3.listBuckets() match {
      case Success(buckets) => println(s"S3 Buckets: ${buckets.mkString(", ")}")
      case Failure(ex) => println(s"Failed to list buckets: ${ex.getMessage}")
    }

    awsManager.s3.putObject("my-bucket", "test-key", "Hello, World!") match {
      case Success(msg) => println(msg)
      case Failure(ex) => println(s"Failed to put object: ${ex.getMessage}")
    }

    // SQS operations
    awsManager.sqs.listQueues() match {
      case Success(queues) => println(s"SQS Queues: ${queues.mkString(", ")}")
      case Failure(ex) => println(s"Failed to list queues: ${ex.getMessage}")
    }

    // DynamoDB operations
    val item = Map(
      "id" -> AttributeValue.builder().s("123").build(),
      "name" -> AttributeValue.builder().s("Test Item").build(),
      "value" -> AttributeValue.builder().n("42").build()
    )

    awsManager.dynamoDb.putItem("my-table", item) match {
      case Success(msg) => println(msg)
      case Failure(ex) => println(s"Failed to put item: ${ex.getMessage}")
    }

    val key = Map("id" -> AttributeValue.builder().s("123").build())
    awsManager.dynamoDb.getItem("my-table", key) match {
      case Success(result) => println(s"DynamoDB Item: $result")
      case Failure(ex) => println(s"Failed to get item: ${ex.getMessage}")
    }

    // Credential rotation example
    awsManager.rotateCredentials(StaticCredentials("new-access-key", "new-secret-key"))
    println("Credentials rotated")

  } else {
    println("Failed to validate credentials")
  }

  awsManager.shutdown()
  println("AWS Service Manager shut down")
}